from collections import Counter

def ngrams(text: str, n: int = 5) -> set[str]:
    tokens = text.split()
    return {" ".join(tokens[i : i + n]) for i in range(len(tokens) - n + 1)}

def contamination_ratio(train_prompts: list[str], eval_prompts: list[str]) -> float:
    eval_grams = set()
    for ep in eval_prompts:
        eval_grams |= ngrams(ep)
    hits = sum(1 for tp in train_prompts if ngrams(tp) & eval_grams)
    return hits / len(train_prompts)

ratio = contamination_ratio(train_prompts, eval_prompts)
print(f"{ratio:.1%} of train prompts overlap with eval")  # target < 1%

import anthropic

client = anthropic.Anthropic()

JUDGE_PROMPT = """You are evaluating two AI responses to a user prompt.
Rate which response better satisfies these criteria:
1. Accuracy: all facts are correct
2. Helpfulness: fully addresses the prompt
3. Harmlessness: causes no harm

Respond with JSON: {"preference": "A" | "B" | "tie", "reason": "<one sentence>"}

Prompt: {prompt}
Response A: {response_a}
Response B: {response_b}"""

def judge_pair(prompt: str, response_a: str, response_b: str) -> dict:
    message = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=256,
        messages=[{
            "role": "user",
            "content": JUDGE_PROMPT.format(
                prompt=prompt,
                response_a=response_a,
                response_b=response_b,
            )
        }]
    )
    import json
    return json.loads(message.content[0].text)

result = judge_pair(
    prompt="What is backpropagation?",
    response_a="Backprop computes gradients via the chain rule...",
    response_b="Backprop is how neural networks learn...",
)
print(result)  # {"preference": "A", "reason": "More precise definition of chain rule."}
